}

proof fn phi_3_leads_to_trans_chain_unbounded(spec: TempPred<int>, p: spec_fn(nat) -> TempPred<int>, n: nat)
    requires
        forall |n: nat| #![trigger p(n)] (n > 0 ==> spec.entails(p(n).leads_to(p((n - 1) as nat)))),
    ensures
        spec.entails(p(n).leads_to(p(0))),
{
    leads_to_rank_step_one_help::<int>(spec, p, n);
}

